"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["30024"],{92852(e){e.exports=JSON.parse('{"tag":{"label":"Durable Timers","permalink":"/tags/durable-timers","allTagsPath":"/tags","count":8,"items":[{"id":"develop/dotnet/durable-timers","title":"Durable Timers - .NET SDK","description":"Set a Durable Timer using the Temporal .NET SDK. Pause Workflow execution for days or months. Timers are persisted and highly resource-efficient using Workflow.DelayAsync.","permalink":"/develop/dotnet/durable-timers"},{"id":"develop/go/timers","title":"Durable Timers - Go SDK","description":"Set Durable Timers in a Workflow using the sleep() or NewTimer() functions in Go with Temporal. Timers persist through Worker and Temporal Service downtime.","permalink":"/develop/go/timers"},{"id":"develop/java/timers","title":"Durable Timers - Java SDK","description":"A Workflow sets a durable Timer for delayed execution. Even if the Worker or Temporal Service is down, the Timer resumes once back up. Efficient and scalable.","permalink":"/develop/java/timers"},{"id":"develop/php/timers","title":"Durable Timers - PHP SDK","description":"A Timer in a Workflow sets a durable pause for a fixed time. Even after downtimes, your Workflow resumes execution. Lightweight and scalable, millions of Timers can run on a single Worker.","permalink":"/develop/php/timers"},{"id":"develop/python/timers","title":"Durable Timers - Python SDK","description":"Set durable Timers with Temporal Workflows using sleep() or timer(), ensuring code execution resumes after downtime. Sleep for months using resource-light operations in Python.","permalink":"/develop/python/timers"},{"id":"develop/ruby/durable-timers","title":"Durable Timers - Ruby SDK","description":"Set a Durable Timer using the Temporal Ruby SDK. Pause Workflow execution for days or months. Timers are persisted and efficient.","permalink":"/develop/ruby/durable-timers"},{"id":"develop/typescript/timers","title":"Durable Timers - TypeScript SDK","description":"A Workflow sets durable Timers for fixed periods using sleep() or timer(). Timers are persisted, ensuring execution continues after downtime, using minimal resources.","permalink":"/develop/typescript/timers"},{"id":"develop/go/selectors","title":"Selectors - Go SDK","description":"Use Temporal\u2019s Go SDK Selectors with Futures, Timers, and Channels. Ensure deterministic Workflow execution and handle multiple parallel tasks efficiently.","permalink":"/develop/go/selectors"}],"unlisted":false}}')}}]);